const rawMobile = {{workflowparams:mobile_number}};

// Normalize mobile input into an array of trimmed, non-empty strings.
let mobileList = [];
if (Array.isArray(rawMobile)) {
  mobileList = rawMobile;
} else if (rawMobile != null && rawMobile !== "") {
  mobileList = [rawMobile];
}
mobileList = mobileList
  .map((m) => (m == null ? "" : String(m)).trim())
  .filter((m) => m !== "");

const lookupBy = mobileList.length > 0 ? "phone" : "email";

// SE Asia dialing rules. cc = country calling code; nationalRe matches the
// national subscriber number (no code, no leading 0); hasNationalZero = the
// number is commonly written with a leading 0 domestically.
const COUNTRIES = [
  { cc: "60", nationalRe: /^1\d{8,9}$/, hasNationalZero: true },
  { cc: "65", nationalRe: /^[89]\d{7}$/, hasNationalZero: false },
  { cc: "66", nationalRe: /^[689]\d{8}$/, hasNationalZero: true },
  { cc: "62", nationalRe: /^8\d{8,11}$/, hasNationalZero: true }
];

// Generate every storage representation a number might appear as, so the
// IN-query matches a contact regardless of how its mobile_number was stored:
// "+60XXXX", "60XXXX", "0XXXX", or the bare national "XXXX" (with the calling
// code held in a separate column).
const buildVariants = (mobileStr) => {
  const variants = new Set();
  if (!mobileStr) return [];
  variants.add(mobileStr);
  const stripped = mobileStr.startsWith("+") ? mobileStr.slice(1) : mobileStr;
  variants.add(stripped);

  const emit = (cc, national, hasZero) => {
    if (!national) return;
    variants.add(national); // bare national subscriber number
    if (hasZero && !national.startsWith("0")) variants.add("0" + national);
    if (cc) {
      variants.add(cc + national); // 60XXXXXXXX
      variants.add("+" + cc + national); // +60XXXXXXXX
    }
  };

  // A) Explicit country-code prefix, e.g. "+6012345678" / "6012345678".
  //    Literal prefix match (no length regex) so unusual/short numbers still
  //    split into their bare national form.
  for (const c of COUNTRIES) {
    if (stripped.startsWith(c.cc) && stripped.length > c.cc.length) {
      emit(c.cc, stripped.slice(c.cc.length), c.hasNationalZero);
    }
  }

  if (stripped.startsWith("0") && stripped.length > 1) {
    // B) Domestic form with a leading 0, e.g. "0178890665".
    //    Use each country's pattern to attach the right code(s) precisely.
    const national = stripped.slice(1);
    variants.add(national);
    for (const c of COUNTRIES) {
      if (c.hasNationalZero && c.nationalRe.test(national)) emit(c.cc, national, true);
    }
  } else {
    // C) Bare national, no code and no leading 0, e.g. "178890665".
    //    Attach codes only where the pattern matches to avoid noise.
    for (const c of COUNTRIES) {
      if (c.nationalRe.test(stripped)) emit(c.cc, stripped, c.hasNationalZero);
    }
  }

  return Array.from(variants);
};

const inputMap = [];
const allVariantsSet = new Set();
for (const input of mobileList) {
  const variants = buildVariants(input);
  inputMap.push({ input, variants });
  for (const v of variants) allVariantsSet.add(v);
}
const allVariants = Array.from(allVariantsSet);

return { lookupBy, allVariants, inputMap };

const phoneContacts = {{node:get_node_THuA8VPh.data.data}} || [];
const emailRes = {{node:get_node_814fnfzT.data}};
const lookupBy = {{node:code_node_yrSiOiir.data.lookupBy}};
const inputMap = {{node:code_node_yrSiOiir.data.inputMap}};

// get-node (email branch) data is a single object when count===1, an array otherwise.
const getNodeToArray = (res) => {
  if (!res || !res.count || res.count <= 0) return [];
  const dd = res.data;
  if (Array.isArray(dd)) return dd;
  if (dd && typeof dd === "object") return [dd];
  return [];
};

const pairs = [];
const customerIdSet = new Set();

if (lookupBy === "phone") {
  // search-node returns the rows array directly at .data.data
  const contacts = Array.isArray(phoneContacts) ? phoneContacts : [];
  // One output pair per input number, preserving 1:1 ordering.
  for (const entry of (inputMap || [])) {
    const variants = entry.variants || [];
    const match = contacts.find(
      (c) => c && variants.indexOf(String(c.mobile_number)) !== -1
    );
    if (match) {
      const cid = match.Customer_id || "";
      pairs.push({ mobile_number: match.mobile_number || entry.input, customer_id: cid });
      if (cid) customerIdSet.add(cid);
    } else {
      pairs.push({ mobile_number: entry.input, customer_id: "" });
    }
  }
} else {
  // Email fallback: single record via get-node.
  const contacts = getNodeToArray(emailRes);
  const match = contacts.length > 0 ? contacts[0] : null;
  if (match) {
    const cid = match.Customer_id || "";
    pairs.push({ mobile_number: match.mobile_number || "", customer_id: cid });
    if (cid) customerIdSet.add(cid);
  } else {
    pairs.push({ mobile_number: "", customer_id: "" });
  }
}

const customerIds = Array.from(customerIdSet);

return { pairs, customerIds };

const pairs = {{node:code_node_Eg4cGg3h.data.pairs}};
const customers = {{node:get_node_h9IHH6H7.data.data}} || [];

// search-node returns the rows array directly at .data.data
const list = Array.isArray(customers) ? customers : [];
const custById = {};
for (const c of list) {
  if (c && c.id != null) custById[String(c.id)] = c;
}

const result = (pairs || []).map((p) => {
  const c = p.customer_id ? custById[String(p.customer_id)] : null;
  return {
    mobile_number: p.mobile_number || "",
    customer_code: c && c.customer_id ? c.customer_id : "",
    customer_name: c && c.customer_com_name ? c.customer_com_name : ""
  };
});

return { result };
